// ============================================================================

#[test]
fn jjtsc_mode_plain_word_is_not_regex() {
    assert!(!zjrsc_is_regex_pattern("ark"));
    assert!(!zjrsc_is_regex_pattern("two words"));
    assert!(!zjrsc_is_regex_pattern("kebab-case"));
}

