    assert!(lines[0].contains("₢AAAAA") && lines[0].contains("[whole]"), "got: {:?}", lines);
    assert!(lines[1].contains("₢AAAAB") && lines[1].contains("[prefix]"), "got: {:?}", lines);
    assert!(lines[2].contains("₢AAAAC") && lines[2].contains("[substring]"), "got: {:?}", lines);
